from llama_cpp import Llama
from sentence_transformers import SentenceTransformer
import chromadb
import os
from http.server import HTTPServer, BaseHTTPRequestHandler
import json

print("Loading VerdeBuddy model...")
llm = Llama(
    model_path="model/Phi-3-mini-4k-instruct-q4.gguf",
    n_ctx=2048,
    n_threads=4,
    n_gpu_layers=0,
    n_batch=512,
    verbose=False
)

print("Loading knowledge base...")
embedder = SentenceTransformer("all-MiniLM-L6-v2")
client = chromadb.Client()
collection = client.create_collection("agri_knowledge")

def load_knowledge_base():
    data_dir = "data"
    for filename in os.listdir(data_dir):
        if filename.endswith(".txt"):
            with open(f"{data_dir}/{filename}", "r") as f:
                content = f.read()
            chunks = content.split("\n\n")
            for i, chunk in enumerate(chunks):
                if chunk.strip():
                    embedding = embedder.encode(chunk).tolist()
                    collection.add(documents=[chunk], embeddings=[embedding], ids=[f"{filename}_{i}"])
    print("Knowledge base loaded. VerdeBuddy is ready!")

load_knowledge_base()

SYSTEM_PROMPT = """You are VerdeBuddy (Verde means Green in Italian), an offline AI assistant for Nigerian farmers.
You give practical advice on crops, soil health, weather patterns, and market prices.
Always base your answers on the context provided.
Never invent specific prices or dates not in your context.
LANGUAGE INSTRUCTIONS:
- If the farmer writes in English, respond in English
- If the farmer writes in Hausa, respond in Hausa
- If the farmer writes in Yoruba, respond in Yoruba
- If the farmer writes in Igbo, respond in Igbo
- Always match the language the farmer is using"""

def ask(query):
    query_embedding = embedder.encode(query).tolist()
    results = collection.query(query_embeddings=[query_embedding], n_results=2)
    context = "\n\n".join(results["documents"][0])
    messages = [
        {"role": "system", "content": SYSTEM_PROMPT},
        {"role": "user", "content": f"Context:\n{context}\n\nFarmer question: {query}"}
    ]
    response = llm.create_chat_completion(messages=messages, max_tokens=150, temperature=0.3)
    return response["choices"][0]["message"]["content"]

